            [3.0, 4.0, 5.0],
            [4.0, 5.0, 6.0],
            [5.0, 6.0, 7.0],
            [10.0, 12.0, 14.0], // Potential outlier
        ];

        let mut pca = PcaBuilder::new()
            .n_components(2)
            .build();
        pca.fit(&data).unwrap();

        let measures = pca.influence_measures(&data).unwrap();

        // Check dimensions
        assert_eq!(measures.dim(), (6, 3)); // 6 samples, 3 measures

        // Check that all measures are non-negative
        for i in 0..6 {
            assert!(measures[[i, 0]] >= 0.0); // Leverage
            assert!(measures[[i, 1]] >= 0.0); // Cook's distance
            // DFFITS can be negative, so we check absolute value
            assert!(measures[[i, 2]].abs() >= 0.0); 
        }

        // The outlier (last sample) should have higher influence measures
        let last_idx = 5;
        let avg_cooks = (0..5).map(|i| measures[[i, 1]]).sum::<f64>() / 5.0;
        assert!(measures[[last_idx, 1]] > avg_cooks);
    }

    #[test]
    fn test_fit_statistics() {
        let data = array![
            [1.0, 2.0, 3.0, 4.0],
            [2.0, 3.0, 4.0, 5.0],
            [3.0, 4.0, 5.0, 6.0],
            [4.0, 5.0, 6.0, 7.0],
            [5.0, 6.0, 7.0, 8.0],
            [6.0, 7.0, 8.0, 9.0],
        ];

        let mut pca = PcaBuilder::new()
            .n_components(2)
            .build();
        pca.fit(&data).unwrap();

        let stats = pca.fit_statistics(&data).unwrap();

        // Check basic properties
        assert_eq!(stats.n_components, 2);
        assert_eq!(stats.n_samples, 6);
        assert_eq!(stats.n_features, 4);

        // Check that variance explained is reasonable
        assert!(stats.total_variance_explained > 0.0 && stats.total_variance_explained <= 1.0);

        // Check R-squared is in valid range
        assert!(stats.r_squared >= 0.0 && stats.r_squared <= 1.0);
        assert!(stats.adjusted_r_squared >= -1.0 && stats.adjusted_r_squared <= 1.0);

        // Check RMSE is non-negative
        assert!(stats.rmse >= 0.0);

        // Check RSS is non-negative
        assert!(stats.residual_sum_of_squares >= 0.0);

        // With 2 components capturing most variance, R-squared should be high
        assert!(stats.r_squared > 0.9);
    }

    #[test]
    fn test_diagnostic_methods_errors() {
        let mut pca = PcaBuilder::new().build();

        // Not fitted errors
        assert!(pca.influence_measures(&Matrix::zeros((1, 1))).is_err());
        assert!(pca.fit_statistics(&Matrix::zeros((1, 1))).is_err());

        // Fit with minimal data
        let data = array![[1.0], [2.0]];
        pca.fit(&data).unwrap();

        // Test dimension mismatch
        let wrong_data = array![[1.0, 2.0], [3.0, 4.0]];
        assert!(pca.influence_measures(&wrong_data).is_err());
        assert!(pca.fit_statistics(&wrong_data).is_err());
    }
}

