        ];

        let mut pca = PcaBuilder::new()
            .n_components(2)
            .build();
        pca.fit(&data).unwrap();

        let measures = pca.influence_measures(&data).unwrap();

        // Check dimensions
        assert_eq!(measures.dim(), (6, 3)); // 6 samples, 3 measures

        // Check that all measures are non-negative
        for i in 0..6 {
            assert!(measures[[i, 0]] >= 0.0); // Leverage
            assert!(measures[[i, 1]] >= 0.0); // Cook's distance
            // DFFITS can be negative, so we check absolute value
            assert!(measures[[i, 2]].abs() >= 0.0); 
        }

        // The outlier (last sample) should have higher influence measures
        let last_idx = 5;
        let avg_cooks = (0..5).map(|i| measures[[i, 1]]).sum::<f64>() / 5.0;
        assert!(measures[[last_idx, 1]] > avg_cooks);
    }

