        // Fit with minimal data
        let data = array![[1.0], [2.0]];
        pca.fit(&data).unwrap();

        // Test dimension mismatch
        let wrong_data = array![[1.0, 2.0], [3.0, 4.0]];
        assert!(pca.influence_measures(&wrong_data).is_err());
        assert!(pca.fit_statistics(&wrong_data).is_err());
    }
}
